#include <coroutine>
#include <iostream>
#include <exception>

template<typename T>
struct Generator {
    struct promise_type {
        T value;
        Generator get_return_object() {
            return Generator{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_always initial_suspend() { return {}; }
        std::suspend_always final_suspend() noexcept { return {}; }
        std::suspend_always yield_value(T v) { value = v; return {}; }
        void return_void() {}
        void unhandled_exception() { std::terminate(); }
    };

    std::coroutine_handle<promise_type> handle;
    explicit Generator(std::coroutine_handle<promise_type> h) : handle(h) {}
    ~Generator() { if (handle) handle.destroy(); }
    Generator(const Generator&) = delete;
    Generator& operator=(const Generator&) = delete;

    bool next() { handle.resume(); return !handle.done(); }
    T value() const { return handle.promise().value; }
};

// Coroutine: suspends at each co_yield and produces a value
Generator<int> counter(int from, int to) {
    for (int i = from; i <= to; ++i) {
        co_yield i;   // suspend + produce
    }
    // implicit co_return at the end
}

// Infinite Fibonacci number generator
Generator<int> fibonacci() {
    int a = 0, b = 1;
    while (true) {
        co_yield a;
        int tmp = a + b;
        a = b;
        b = tmp;
    }
}

int main() {
    std::cout << "counter(1, 5):\n";
    auto gen = counter(1, 5);
    while (gen.next()) {
        std::cout << gen.value() << " ";
    }
    std::cout << "\n";

    std::cout << "fibonacci (first 8):\n";
    auto fib = fibonacci();
    for (int i = 0; i < 8; ++i) {
        fib.next();
        std::cout << fib.value() << " ";
    }
    std::cout << "\n";

    return 0;
}

#include <coroutine>
#include <iostream>
#include <exception>

// Lazy coroutine: initial_suspend returns suspend_always
struct LazyTask {
    struct promise_type {
        LazyTask get_return_object() {
            return LazyTask{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_always initial_suspend() { return {}; }   // does NOT start immediately
        std::suspend_always final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() { std::terminate(); }
    };

    std::coroutine_handle<promise_type> handle;
    explicit LazyTask(std::coroutine_handle<promise_type> h) : handle(h) {}
    ~LazyTask() { if (handle) handle.destroy(); }
    LazyTask(const LazyTask&) = delete;
    LazyTask& operator=(const LazyTask&) = delete;

    void resume() { handle.resume(); }
    bool done() const { return handle.done(); }
};

// Eager coroutine: initial_suspend returns suspend_never
struct EagerTask {
    struct promise_type {
        EagerTask get_return_object() { return {}; }
        std::suspend_never initial_suspend() { return {}; }   // starts immediately
        std::suspend_never final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() { std::terminate(); }
    };
};

LazyTask lazy_coroutine() {
    std::cout << "lazy: step 1\n";
    co_await std::suspend_always{};   // explicit suspension point
    std::cout << "lazy: step 2\n";
    co_await std::suspend_never{};    // does NOT suspend, continues immediately
    std::cout << "lazy: step 3\n";
}

EagerTask eager_coroutine() {
    std::cout << "eager: running immediately\n";
    co_return;
}

int main() {
    std::cout << "--- Lazy ---\n";
    auto task = lazy_coroutine();
    std::cout << "coroutine created, not started yet\n";
    task.resume();  // starts, runs until first suspend_always
    std::cout << "after first resume\n";
    task.resume();  // continues: step 2, suspend_never skips, step 3
    std::cout << "done: " << task.done() << "\n";

    std::cout << "--- Eager ---\n";
    std::cout << "before creating eager coroutine\n";
    eager_coroutine();   // starts and finishes right here
    std::cout << "after eager coroutine\n";

    return 0;
}

#include <coroutine>
#include <iostream>
#include <string>
#include <exception>

template<typename T>
struct Generator {
    struct promise_type {
        T value;
        Generator get_return_object() {
            return Generator{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_always initial_suspend() { return {}; }
        std::suspend_always final_suspend() noexcept { return {}; }
        std::suspend_always yield_value(T v) { value = v; return {}; }
        void return_void() {}
        void unhandled_exception() { std::terminate(); }
    };

    std::coroutine_handle<promise_type> handle;
    explicit Generator(std::coroutine_handle<promise_type> h) : handle(h) {}
    ~Generator() { if (handle) handle.destroy(); }
    Generator(const Generator&) = delete;
    Generator& operator=(const Generator&) = delete;

    bool next() { handle.resume(); return !handle.done(); }
    T value() const { return handle.promise().value; }
};

Generator<std::string> stateful_gen() {
    // 'prefix' and 'modification_count' live in the coroutine frame (heap).
    // They are NOT destroyed at each suspension — they live until destroy().
    std::string prefix = "item_";
    int modification_count = 0;
    for (int i = 0; i < 3; ++i) {
        ++modification_count;
        co_yield prefix + std::to_string(i)
               + " (mod#" + std::to_string(modification_count) + ")";
    }
    // implicit co_return: done() becomes true
}

int main() {
    std::cout << "Locals in coroutine frame survive suspensions:\n";
    auto gen = stateful_gen();
    while (gen.next()) {
        std::cout << "  " << gen.value() << "\n";
    }

    std::cout << "\ndone() tracks coroutine state:\n";
    auto gen2 = stateful_gen();
    std::cout << "start:         done=" << gen2.handle.done() << "\n";
    gen2.next();
    std::cout << "after yield 1: done=" << gen2.handle.done() << "\n";
    gen2.next();
    gen2.next();
    // One more resume: coroutine exits loop, hits return_void, final_suspend
    gen2.handle.resume();
    std::cout << "after finish:  done=" << gen2.handle.done() << "\n";

    return 0;
}
